SELECT followee_id
FROM user_follows
WHERE follower_id = #{userId}

SELECT u.id, u.username, u.avatar_url AS avatarUrl, u.bio,
       (SELECT COUNT(*) FROM user_follows WHERE follower_id = u.id) AS followCount,
       (SELECT COUNT(*) FROM user_follows WHERE followee_id = u.id) AS fansCount,
       EXISTS (
           SELECT 1 FROM user_follows
           WHERE follower_id = #{currentUserId} AND followee_id = u.id
       ) AS isFollowed,
       EXISTS (
           SELECT 1 FROM user_follows
           WHERE follower_id = #{currentUserId} AND followee_id = u.id
       ) AND EXISTS (
           SELECT 1 FROM user_follows
           WHERE follower_id = u.id AND followee_id = #{currentUserId}
       ) AS isMutual
FROM user_follows f
JOIN users u ON u.id = f.follower_id
WHERE f.followee_id = #{userId}
ORDER BY f.created_at DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM user_follows
WHERE followee_id = #{userId}

